import { Component } from '@angular/core';

@Component({
  selector: 'app-compound-interest',
  templateUrl: './compound-interest.component.html',
  styleUrls: ['./compound-interest.component.scss']
})
export class CompoundInterestComponent {
  step1: number = 1212121; // Giá trị mặc định từ ảnh
  step2: number = 2121212; // Giá trị mặc định từ ảnh
  interestRate: number = 10; // Giá trị mặc định từ ảnh
  years: number = 10; // Giá trị mặc định từ ảnh
  period: string = 'Hàng năm'; // Mặc định
  result: number = 0;
  yearsData: number[] = [];
  principalData: number[] = [];
  interestData: number[] = [];

  calculateCompoundInterest() {
    const p = this.step1; // Đầu tư ban đầu
    const monthlyContribution = this.step2; // Khoản đóng góp hàng tháng
    const i = this.interestRate / 100; // Chuyển lãi suất % thành thập phân
    const n = this.years; // Số năm
    const m = this.period === 'Hàng tháng' ? 12 : 1; // Số lần ghép lãi trong năm

    // Tính giá trị cuối cùng với lãi kép và khoản đóng góp
    let total = p;
    this.yearsData = [0];
    this.principalData = [p];
    this.interestData = [0];

    for (let year = 1; year <= n; year++) {
      const months = year * 12;
      total = p * Math.pow(1 + (i / m), months * m / 12); // Tính lãi kép cho phần gốc
      for (let month = 1; month <= 12; month++) {
        total += monthlyContribution; // Thêm khoản đóng góp hàng tháng
        if (month % 12 === 0) { // Cập nhật giá trị cuối năm
          this.yearsData.push(year);
          this.principalData.push(total - (monthlyContribution * 12 * year)); // Phần gốc tích lũy
          this.interestData.push(total - p - (monthlyContribution * 12 * year)); // Phần lãi
        }
      }
    }
    this.result = Math.round(total);

    // Cập nhật dữ liệu cho biểu đồ
    this.generateChart();
  }

  generateChart() {
    // Logic để tạo biểu đồ (sẽ được gọi trong HTML qua code block chartjs)
  }
}
